-- forum tags and topics from the mockup

-- forum posts mirroring the discussion mood from the mockup

-- contests from the mockup

-- radio from the mockup

-- comments and ratings derived from the mockup discussion/review blocks

-- keep derived counters aligned with seeded rows
UPDATE author_profiles ap SET works_count_cached = stats.cnt FROM ( SELECT author_user_id, count(*)::int AS cnt FROM works GROUP BY author_user_id) stats WHERE ap.user_id = stats.author_user_id;
UPDATE works w SET comments_count = stats.cnt FROM ( SELECT work_id, count(*)::int AS cnt FROM work_comments GROUP BY work_id) stats WHERE w.id = stats.work_id;
UPDATE works SET comments_count = 0 WHERE comments_count IS NULL;
UPDATE works w SET ratings_count = stats.cnt, average_rating = stats.avg_rating FROM ( SELECT work_id, count(*)::int AS cnt, avg(rating)::numeric(4,2) AS avg_rating FROM work_ratings GROUP BY work_id) stats WHERE w.id = stats.work_id;
UPDATE works SET ratings_count = 0 WHERE ratings_count IS NULL;
UPDATE works SET average_rating = 0 WHERE average_rating IS NULL;
UPDATE forum_topics ft SET replies_count = stats.cnt, last_post_at = stats.last_post_at FROM ( SELECT topic_id, count(*)::int AS cnt, max(created_at) AS last_post_at FROM forum_posts GROUP BY topic_id) stats WHERE ft.id = stats.topic_id;

COMMIT;
